export function isVideoStubEnabled(){const t=process.env.TAVERNOS_VIDEO_STUB;return t==="true"||t==="1"}export function stubVideoGeneration(t){const n=e(t.prompt),o=t.duration??5;return{videoUrl:`https://stub.tavernos.local/video/${n}.mp4`,thumbnailUrl:`https://stub.tavernos.local/thumb/${n}.png`,duration:o,createdAt:new Date().toISOString()}}function e(t){let n=5381;for(let o=0;o<t.length;o++)n=(n<<5)+n+t.charCodeAt(o)|0;return(n>>>0).toString(16)}
